mapper.update:
update config_value

    option_id = case id

        when #{item.id} then #{item.optionId}

    end,
    name = case id

        when #{item.id} then #{item.name}

    end,
    spread = case id

        when #{item.id} then COALESCE(#{item.spread}, 0)

    end

where id in

    #{item.id}

mapper.delete:
delete from goods_class where goods_type = #{goodsType} and

    dish_id = #{id}


    combo_id = #{id}

mapper.select:
select d.id,d.cover,d.name,d.price,d.state,ifnull(temp.className,'未分类') as className
from dish d left join (
    select gc.dish_id,GROUP_CONCAT(mc.name SEPARATOR ',') as className
    from goods_class gc join menu_class mc on gc.menu_class_id = mc.id
    where gc.menu_class_id != 0
    group by gc.dish_id
) temp on d.id = temp.dish_id


        d.name like concat('%', #{dishName}, '%')


        and d.state = #{state}


        and temp.className like concat('%', #{className},'%')


limit #{skip}, #{pageSize}

select c.id,c.name,c.cover,c.state,c.def_price,c.reduce_price,ifnull(temp.className,'未分类') as className
from combo c left join (
select gc.combo_id,GROUP_CONCAT(mc.name SEPARATOR ',') as className
from goods_class gc join menu_class mc on gc.menu_class_id = mc.id
where gc.menu_class_id != 0
group by gc.combo_id
) temp on c.id = temp.combo_id


        c.name like concat('%', #{name}, '%')


order by c.sort
limit #{skip}, #{pageSize}

select gd.group_id,gd.dish_id,gd.num,gd.required,d.name,d.price from group_detail gd join dish d on gd.dish_id = d.id where gd.group_id in
#{groupId}
order by d.price

select cm.dish_id,cm.option_id,cm.value_id,cv.name,cv.spread from config_material cm join config_value cv on cm.value_id = cv.id where cm.dish_id in
#{dishId}
group by cm.value_id,cm.dish_id,cm.option_id,cv.name,cv.spread

select cg.group_id
from combo_group cg

    join (
             select group_id
             from group_detail gd
             where dish_id = #{dishId}
             group by group_id
         ) gd on cg.group_id = gd.group_id



        and cg.combo_id = #{comboId}


        and cg.group_id in

            #{groupId}



group by cg.group_id;
